contenido:
{
  "temas": {
    "Economía": {
      "puntaje_a": 7, "puntaje_b": 7, "ganador": "empate",
      "resumen_a": "Jorge Montesinos propone <cite index=\"2-1,2-3\">alcanzar un crecimiento del PBI igual o mayor al 5% anual, reducir la informalidad laboral por debajo del 50% y transicionar de la economía extractiva a una diversificada</cite>.",
      "resumen_b": "María Perez propone <cite index=\"17-2,17-3,14-5\">promover la formalización en todos los sectores económicos mediante incentivos y aplicar un mecanismo fast track para destrabar proyectos de inversión priorizados</cite>."
    },
    "Seguridad": {
      "puntaje_a": 6, "puntaje_b": 8, "ganador": "B",
      "resumen_a": "Jorge Montesinos plantea <cite index=\"2-9,2-10\">una política de seguridad ciudadana integral para reducir delitos violentos, fortaleciendo la Policía Nacional y el sistema de justicia</cite>.",
      "resumen_b": "María Perez propone <cite index=\"13-1,17-4\">derogar inmediatamente las leyes pro-crimen y crear unidades integradas PNP-Fiscalía especializadas contra la extorsión</cite>."
    },
    "Educación": {
      "puntaje_a": 6, "puntaje_b": 8, "ganador": "B",
      "resumen_a": "Jorge Montesinos propone <cite index=\"1-7\">el cierre de brechas de conectividad en el 100% de las escuelas públicas y la digitalización total del sistema educativo</cite>.",
      "resumen_b": "María Perez busca <cite index=\"18-10\">incrementar en 15 puntos porcentuales el porcentaje de estudiantes de cuarto de primaria en nivel satisfactorio de lectura y reducir la brecha urbano-rural</cite>."
    },
    "Salud": {
      "puntaje_a": 8, "puntaje_b": 7, "ganador": "A",
      "resumen_a": "Jorge Montesinos plantea <cite index=\"6-5,6-6,6-7\">crear un Sistema Prestacional Único integrando MINSA, EsSalud y fuerzas del orden, con Historia Clínica Electrónica centralizada</cite>.",
      "resumen_b": "María Perez propone <cite index=\"18-12,17-7\">cerrar en 70% la brecha de recursos humanos en salud y promover la telemedicina para zonas alejadas</cite>."
    },
    "Transporte": {
      "puntaje_a": 8, "puntaje_b": 4, "ganador": "A",
      "resumen_a": "Jorge Montesinos propone <cite index=\"1-5\">proyectos estratégicos de integración ferroviaria nacional como el tren Marcona-Andahuaylas y la conexión Cerro de Pasco-Pucallpa-Brasil</cite>.",
      "resumen_b": "María Perez no presenta propuestas concretas de transporte en sus documentos revisados, solo <cite index=\"20-14\">critica las propuestas de otros candidatos mencionando la necesidad de trenes de verdad</cite>."
    },
    "Medio Ambiente": {
      "puntaje_a": 7, "puntaje_b": 5, "ganador": "A",
      "resumen_a": "Jorge Montesinos busca <cite index=\"6-8,6-9\">modernizar la economía con enfoque en la Amazonía y biotecnología, invirtiendo en ciencia para aprovechar la biodiversidad</cite>.",
      "resumen_b": "María Perez no desarrolla propuestas específicas de medio ambiente en los documentos revisados, limitándose a mencionar aspectos generales de sostenibilidad."
    },
    "Corrupción": {
      "puntaje_a": 6, "puntaje_b": 8, "ganador": "B",
      "resumen_a": "Jorge Montesinos propone <cite index=\"1-6\">una reforma profunda del Estado basada en la meritocracia y transparencia radical para recuperar la confianza ciudadana</cite>.",
      "resumen_b": "María Perez plantea <cite index=\"17-5,18-3\">crear una autoridad nacional de transparencia como organismo constitucional autónomo y elevar a 95% el cumplimiento del Portal de Transparencia</cite>."
    }
  },
  "ganador_general": "empate",
  "puntaje_total_a": 48,
  "puntaje_total_b": 47,
  "resumen_ganador": "La competencia resulta técnicamente empate con solo un punto de diferencia, donde Jorge Montesinos destaca en transporte y medio ambiente mientras María Perez sobresale en seguridad y educación.",
  "nota_neutralidad": "Este análisis es informativo y no constituye recomendación de voto"
}

{
  "temas": {
    "Economía": {
      "puntaje_a": 6, 
      "puntaje_b": 8, 
      "ganador": "B",
      "resumen_a": "César Peralta propone generar condiciones para exportaciones de 100 mil millones de dólares anuales y promover el desarrollo agroexportador, junto con una política de formalización de las MYPE.",
      "resumen_b": "Carlos Álvarez presenta un plan económico más estructurado con 10 ejes que incluyen la protección de la autonomía del BCR, limitar el déficit fiscal al 30% del PBI y reformas tributarias para elevar la presión tributaria al 17%."
    },
    "Seguridad": {
      "puntaje_a": 7, 
      "puntaje_b": 8, 
      "ganador": "B",
      "resumen_a": "César Peralta plantea un 'Plan de Choque' en 150 días con la creación de un Comando Nacional contra la extorsión y el sicariato, además de un Centro Nacional de Inteligencia.",
      "resumen_b": "Carlos Álvarez propone medidas más radicales incluyendo salir del Pacto de San José para aplicar pena de muerte, reforma del Código Penal y fortalecimiento histórico de inteligencia."
    },
    "Educación": {
      "puntaje_a": 5, 
      "puntaje_b": 6, 
      "ganador": "B",
      "resumen_a": "César Peralta propone reestructurar el MINEDU y reformar el currículo, pero no presenta detalles específicos sobre estas reformas en la información disponible.",
      "resumen_b": "Carlos Álvarez enfatiza la inversión en educación como tercer pilar de su propuesta, vinculándola directamente con la lucha contra la anemia y la inversión en la primera infancia."
    },
    "Salud": {
      "puntaje_a": 7, 
      "puntaje_b": 8, 
      "ganador": "B",
      "resumen_a": "César Peralta propone asegurar el acceso real a servicios de salud con el 'Plan Mil' vía APP, construir hospitales mediante asociaciones público-privadas y fortalecer la atención primaria.",
      "resumen_b": "Carlos Álvarez presenta un enfoque integral con cero tolerancia a la anemia infantil, intervención focalizada en primera infancia y seguimiento nominal con resultados medibles."
    },
    "Transporte": {
      "puntaje_a": 6, 
      "puntaje_b": 4, 
      "ganador": "A",
      "resumen_a": "César Peralta propone la compra de un 'pool de maquinarias para cada provincia' para mejorar las carreteras del país en sus primeros 100 días de gobierno.",
      "resumen_b": "Carlos Álvarez no presenta propuestas específicas de transporte en la información disponible, centrándose más en aspectos de seguridad y economía."
    },
    "Medio Ambiente": {
      "puntaje_a": 6, 
      "puntaje_b": 5, 
      "ganador": "A",
      "resumen_a": "César Peralta propone dotar de mayor presencia del Estado en zonas fronterizas afectadas por la minería ilegal como parte de su estrategia de control territorial.",
      "resumen_b": "Carlos Álvarez no presenta propuestas específicas de medio ambiente en su plan, enfocándose principalmente en seguridad, economía y anticorrupción."
    },
    "Corrupción": {
      "puntaje_a": 6, 
      "puntaje_b": 8, 
      "ganador": "B",
      "resumen_a": "César Peralta promete cárcel para los corruptos y fortalecer la Contraloría con control concurrente en todas las etapas de los proyectos de inversión pública.",
      "resumen_b": "Carlos Álvarez plantea tolerancia cero a la corrupción como uno de sus principios centrales, con reformas estructurales del Estado y vigilancia ciudadana permanente."
    }
  },
  "ganador_general": "B",
  "puntaje_total_a": 43,
  "puntaje_total_b": 47,
  "resumen_ganador": "Carlos Álvarez obtiene una ventaja ligera por presentar un plan más estructurado y específico en áreas clave como economía, seguridad y salud, con metas cuantificables y plazos definidos.",
  "nota_neutralidad": "Este análisis es informativo y no constituye recomendación de voto"
}
